mapper.select:
SELECT 
FROM jst_student_channel_binding b
LEFT JOIN jst_channel c
       ON c.channel_id = b.channel_id
      AND c.del_flag = '0'
WHERE b.del_flag = '0'

    AND b.user_id = #{userId}


    AND b.channel_id = #{channelId}


    AND b.status = #{status}

ORDER BY b.bind_time DESC, b.binding_id DESC

